mapper.select:
select id
from artist
where id = #{id}

merge into song_artist sa using ( values
(#{item.songId}::bigint, #{item.artistId}::bigint, #{item.roles}::jsonb)
) as s(song_id, artist_id, roles) on (sa.song_id = s.song_id and sa.artist_id = s.artist_id) when matched then update set roles = s.roles when not matched then insert (song_id, artist_id, roles) values (s.song_id, s.artist_id, s.roles) returning sa.song_id, sa.artist_id, sa.roles, merge_action() as action

with artists as ( select a.id, a.name, a.type, role, sa.song_id from artist a inner join song_artist sa on a.id = sa.artist_id join lateral jsonb_array_elements_text(sa.roles) as role on true union all select a.id, a.name, a.type, 'ALBUM_ARTIST' role, s.id song_id from artist a inner join album al on a.id = al.primary_artist_id inner join song s on al.id = s.album_id ) select id, name, type, jsonb_agg(distinct role) matched_roles from artists
exists(select * from transcription t where t.song_id = artists.song_id)
#{role}
and name ~* #{criteria.searchName}
and type = #{criteria.type}::artist_type
group by id, name, type
name
REGEXP_REPLACE(name, '^(The|A|An)\s+', '', 'i')
type
${ord.direction.clause}
${ord.nullsOrder.clause}
